/**
 * RichElementParser
 * 
 * Intercepts specific XML/HTML-like tags generated by the LLM in the chat 
 * and converts them into styled rich UI components before rendering the markdown.
 */
class RichElementParser {
    static parse(text) {
        if (!text) return "";
        let parsedText = text;

        // 1. Text Message Tags: <text-message sender="Alice">Hello</text-message>
        const textMessageRegex = /<text-message\s+sender=["']([^"']+)["']>([\s\S]*?)<\/text-message>/gi;
        parsedText = parsedText.replace(textMessageRegex, (match, sender, content) => {
            return `<div class="rich-text-message" style="margin: 0.75rem 0;"><div class="rich-text-sender" style="font-size: 0.75rem; color: var(--text-secondary); margin-bottom: 0.2rem;">📱 ${this.escapeHtml(sender)}</div><div class="rich-text-content" style="background: var(--surface-color, #2a2a35); padding: 0.5rem 0.75rem; border-radius: 0.5rem; display: inline-block; border: 1px solid var(--border, #3a3a4a); font-size: 0.9rem;">${this.escapeHtml(content.trim())}</div></div>`;
        });

        // 2. Stat Bar Tags: <stat-bar name="Health" value="80" max="100" />
        // We match continuous blocks of stat-bar tags to group them in a single UI box
        const statBarBlockRegex = /(?:<stat-bar\b[^>]*>(?:<\/stat-bar>)?\s*)+/gi;
        parsedText = parsedText.replace(statBarBlockRegex, (blockMatch) => {
            const innerRegex = /<stat-bar([^>]+)>(?:<\/stat-bar>)?/gi;
            let barsHtml = '';
            let match;
            
            while ((match = innerRegex.exec(blockMatch)) !== null) {
                const attrs = match[1];
                const nameMatch = attrs.match(/name=["']([^"']+)["']/i);
                const valueMatch = attrs.match(/value=["']([^"']+)["']/i);
                const maxMatch = attrs.match(/max=["']([^"']+)["']/i);
                const colorMatch = attrs.match(/color=["']([^"']+)["']/i);
                
                const name = nameMatch ? nameMatch[1] : "Stat";
                const rawValue = valueMatch ? valueMatch[1] : "";
                const rawMax = maxMatch ? maxMatch[1] : null;
                const customColor = colorMatch ? colorMatch[1] : null;
                
                // Decide between numerical progress bar or text status badge
                const isNumeric = rawMax !== null || (/^-?\d+(\.\d+)?%?$/.test(rawValue.trim()));
                
                if (isNumeric) {
                    const valNum = parseFloat(rawValue) || 0;
                    const maxNum = rawMax ? parseFloat(rawMax) : 100;
                    const percentage = Math.min(100, Math.max(0, (valNum / maxNum) * 100));
                    const displayValue = rawMax ? `${rawValue} / ${rawMax}` : rawValue;
                    
                    let barColor = customColor;
                    if (!barColor) {
                        if (percentage > 50) {
                            barColor = 'var(--success, #22c55e)'; // Green
                        } else if (percentage > 25) {
                            barColor = 'var(--warning, #f59e0b)'; // Orange
                        } else {
                            barColor = 'var(--error, #ef4444)'; // Red
                        }
                    }
                    
                    barsHtml += `<div class="rich-stat-item-container" style="background: transparent; border: none; padding: 0; margin: 0; box-shadow: none;"><div class="rich-stat-bar-label" style="display: flex; justify-content: space-between; align-items: center; font-size: 0.85rem; font-weight: 600; margin-bottom: 0.25rem;"><span class="rich-stat-name">${this.escapeHtml(name)}</span><span class="rich-stat-value" style="font-size: 0.75rem; color: var(--text-secondary);">${this.escapeHtml(displayValue)}</span></div><div class="rich-stat-bar-track" style="width: 100%; height: 8px; background: var(--surface-color, #2a2a35); border-radius: 4px; overflow: hidden; border: 1px solid var(--border, #3a3a4a); display: flex;"><div class="rich-stat-bar-fill" style="width: ${percentage}%; height: 100%; background: ${barColor}; transition: width 0.3s ease, background-color 0.3s ease;"></div></div></div>`;
                } else {
                    barsHtml += `<div class="rich-stat-text-row" style="background: transparent; border: none; padding: 0.1rem 0; margin: 0; box-shadow: none; display: flex; justify-content: space-between; align-items: center; font-size: 0.85rem;"><span class="rich-stat-name" style="font-weight: 600; color: var(--text-secondary);">${this.escapeHtml(name)}</span><span class="rich-stat-value" style="color: var(--text-primary); background: var(--surface-color, #2a2a35); padding: 0.2rem 0.6rem; border-radius: 0.25rem; border: 1px solid var(--border, #3a3a4a);">${this.escapeHtml(rawValue)}</span></div>`;
                }
            }
            
            return `<div class="rich-stat-group" style="display: flex; flex-direction: column; gap: 0.5rem; background: var(--bg-tertiary, #1e1e2e); padding: 0.75rem; border-radius: 0.5rem; margin: 0.75rem 0; border: 1px solid var(--border, #3a3a4a);">${barsHtml}</div>`;
        });

        // 3. Task / Objective Tags: <task title="New Objective">Find the key.</task>
        const taskRegex = /<task\s+title=["']([^"']+)["']>([\s\S]*?)<\/task>/gi;
        parsedText = parsedText.replace(taskRegex, (match, title, desc) => {
            return `<div class="rich-task-box" style="background: rgba(245, 158, 11, 0.1); border-left: 3px solid #f59e0b; padding: 0.75rem; margin: 0.75rem 0; border-radius: 0.25rem;"><div class="rich-task-title" style="font-weight: 600; color: #f59e0b; font-size: 0.9rem; margin-bottom: 0.25rem;">📌 ${this.escapeHtml(title)}</div><div class="rich-task-desc" style="font-size: 0.85rem; color: var(--text-secondary);">${this.escapeHtml(desc.trim())}</div></div>`;
        });

        // 4. AI Reasoning (CoT) Tags: <think>...</think>
        const thinkRegex = /<think>([\s\S]*?)<\/think>/gi;
        parsedText = parsedText.replace(thinkRegex, (match, content) => {
            return `<details class="rich-ai-reasoning" style="margin: 0.75rem 0; background: var(--bg-tertiary, #1e1e2e); border: 1px solid var(--border, #3a3a4a); border-radius: 0.5rem; overflow: hidden;"><summary style="cursor: pointer; padding: 0.5rem 0.75rem; font-weight: 600; font-size: 0.85rem; color: var(--text-secondary); background: var(--surface-color, #2a2a35); border-bottom: 1px solid var(--border, #3a3a4a); user-select: none;">AI Reasoning Process</summary><div style="padding: 0.75rem; font-size: 0.85rem; color: var(--text-secondary); white-space: pre-wrap;">${this.escapeHtml(content.trim())}</div></details>`;
        });

        // Final safety net: strip any stray unpaired <think> or </think> that survived upstream.
        parsedText = parsedText.replace(/<think>/gi, '').replace(/<\/think>/gi, '');

        return parsedText;
    }

    static escapeHtml(str) {
        return str
            .replace(/&/g, "&amp;")
            .replace(/</g, "&lt;")
            .replace(/>/g, "&gt;")
            .replace(/"/g, "&quot;")
            .replace(/'/g, "&#039;");
    }
}

window.RichElementParser = RichElementParser;